import WebSqlPouch from 'pouchdb-adapter-websql-core'

WebSqlPouch.valid = function () { return true }
WebSqlPouch.use_prefix = false

export default function (PouchDB) {
  PouchDB.adapter('nodesqlite', WebSqlPouch, false);
}
